import java.util.*;

public class Solution {
    /**
     * Largest Rectangle in Histogram (LeetCode 84).
     *
     * Monotonic increasing stack approach. The stack holds indices of bars
     * whose heights are in non-decreasing order. When we hit a bar shorter
     * than the top of the stack, that top bar can no longer extend to the
     * right, so we "settle" it: pop it and compute the maximum rectangle for
     * which it is the limiting (shortest) bar.
     *
     * @param heights bar heights, width of each bar is 1
     * @return area of the largest rectangle in the histogram
     */
    public int largestRectangleArea(int[] heights) {
        // Edge cases at top.
        if (heights == null || heights.length == 0) return 0;

        int n = heights.length;
        int maxArea = 0;
        // Stack of bar indices with non-decreasing heights.
        Deque<Integer> stack = new ArrayDeque<>();

        // Iterate one past the end: i == n acts as a sentinel of height 0
        // that forces every remaining bar on the stack to be settled.
        for (int i = 0; i <= n; i++) {
            int curHeight = (i == n) ? 0 : heights[i];

            // While the current bar is shorter than the bar on top of the
            // stack, that top bar's rectangle is bounded on the right by i.
            while (!stack.isEmpty() && curHeight < heights[stack.peek()]) {
                int height = heights[stack.pop()];
                // Left boundary is the new top (the previous shorter bar);
                // if stack is empty, the rectangle extends to the far left.
                int leftBoundary = stack.isEmpty() ? -1 : stack.peek();
                int width = i - leftBoundary - 1;
                maxArea = Math.max(maxArea, height * width);
            }
            stack.push(i);
        }

        return maxArea;
    }
}

import java.util.*;

public class Main {
    static int pass = 0, fail = 0;

    static void check(String name, int[] in, int expected) {
        int got = new Solution().largestRectangleArea(in);
        boolean ok = got == expected;
        if (ok) pass++; else fail++;
        System.out.println((ok ? "PASS" : "FAIL") + " " + name +
            " expected=" + expected + " got=" + got);
    }

    public static void main(String[] args) {
        check("example", new int[]{2,1,5,6,2,3}, 10);
        check("single", new int[]{5}, 5);
        check("zero", new int[]{0}, 0);
        check("ascending", new int[]{1,2,3,4,5}, 9);
        check("descending", new int[]{5,4,3,2,1}, 9);
        check("allEqual", new int[]{3,3,3,3}, 12);
        check("twoBars", new int[]{2,4}, 4);
        check("withZeroMid", new int[]{4,0,4}, 4);
        check("emptyArr", new int[]{}, 0);
        check("valley", new int[]{6,2,5,4,5,1,6}, 12);

        // Large stress test: ascending 1..100000 -> max area when picking
        // some bar h as min: area = h * (n - h + 1). Max over h.
        int n = 100000;
        int[] big = new int[n];
        long best = 0;
        for (int i = 0; i < n; i++) {
            big[i] = i + 1;
            long area = (long)(i + 1) * (n - i);
            best = Math.max(best, area);
        }
        long t0 = System.nanoTime();
        int got = new Solution().largestRectangleArea(big);
        long t1 = System.nanoTime();
        boolean ok = got == (int) best;
        if (ok) pass++; else fail++;
        System.out.println((ok ? "PASS" : "FAIL") + " stress100k expected=" +
            (int) best + " got=" + got + " timeMs=" + (t1 - t0) / 1_000_000.0);

        System.out.println("\nTOTAL: " + pass + " passed, " + fail + " failed");
        if (fail > 0) System.exit(1);
    }
}

